Here's how to test `DataFetcher` with MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await sut.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // framework cancels via TestContext.CancellationToken
    public async Task FetchAsync_WithTimeout_CompletesInTime()
    {
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Pass the framework token so the test is cancelled on timeout
        var result = await sut.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        var handler = new FakeHandler("slow", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();

        // Cancel immediately
        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com", cts.Token));
    }

    // Lightweight fake — no mocking library needed
    private sealed class FakeHandler(
        string content, HttpStatusCode status, TimeSpan delay = default) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
                await Task.Delay(delay, cancellationToken);

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` test class | Performance + design clarity |
| Constructor-injected `TestContext` | Enables `readonly`, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — framework signals cancellation |
| `Assert.ThrowsExactlyAsync<T>` | Precise exception check (not `[ExpectedException]`) |
| Custom `HttpMessageHandler` | Avoids mocking libraries; full control over HTTP behavior |

The critical detail: **`[Timeout]` alone doesn't cancel your code** — you must pass `TestContext.CancellationToken` into the async call chain for cooperative cancellation to work.
